	shaders[0] = kgfxCreateShader(ctx, vertex_spv, sizeof(vertex_spv), KGFX_SHADERTYPE_VERTEX, KGFX_MEDIUM_SPIRV);
	if (shaders[0] == KGFX_HANDLE_NULL) {
		fprintf(stderr, "kgfxCreateShader vertex shader failed\n");
		return 1;
	}

